"use strict";(self.webpackChunktemp_blog=self.webpackChunktemp_blog||[]).push([["454"],{6239(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/AWR-ASH","metadata":{"permalink":"/engineering-devlog/blog/AWR-ASH","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/AWR-ASH.md","source":"@site/blog/AWR-ASH.md","title":"AWR-ASH","description":"Title: AWR AND ASH commands!","date":"2026-07-13T03:29:09.000Z","tags":[],"readingTime":1.35,"hasTruncateMarker":false,"authors":[],"frontMatter":{},"unlisted":false,"nextItem":{"title":"rman-log-check","permalink":"/engineering-devlog/blog/rman-log-check"}},"content":"Title: AWR AND ASH commands! \\n\\nASH Top sessions: \\n\\nSELECT session_id, session_serial#, COUNT(*) samples, MAX(sql_id) last_sql\\nFROM v$active_session_history\\nWHERE sample_time > SYSTIMESTAMP - INTERVAL \'15\' MINUTE\\nGROUP BY session_id, session_serial#\\nORDER BY samples DESC\\nFETCH FIRST 20 ROWS ONLY;\\n\\nASG Tio sql 5mins: \\n\\nSELECT ash.sql_id,\\n       COUNT(*) samples,\\n       SUM(CASE WHEN ash.event IS NULL THEN 1 ELSE 0 END) cpu_samples\\nFROM v$active_session_history ash\\nWHERE sample_time > SYSTIMESTAMP - INTERVAL \'5\' MINUTE\\nGROUP BY ash.sql_id\\nORDER BY samples DESC\\nFETCH FIRST 20 ROWS ONLY;\\n\\nASH Top waits last 10 mins: \\n\\n-- top wait events in last 10 minutes (samples)\\nSELECT event,\\n       COUNT(*) samples,\\n       ROUND(100 * COUNT(*) / (SELECT COUNT(*) FROM v$active_session_history WHERE sample_time > SYSTIMESTAMP - INTERVAL \'10\' MINUTE),2) pct\\nFROM v$active_session_history\\nWHERE sample_time > SYSTIMESTAMP - INTERVAL \'10\' MINUTE\\nGROUP BY event\\nORDER BY samples DESC;\\n\\nAWR Create snapshot:\\n\\n-- create an immediate AWR snapshot (run as SYS)\\nEXEC DBMS_WORKLOAD_REPOSITORY.CREATE_SNAPSHOT;\\n\\n\\nAWR generate report via api:\\n\\n-- generate AWR HTML for specific snapshot ids (returns CLOB)\\nSET LONG 100000000\\nSET PAGESIZE 0\\nSELECT DBMS_WORKLOAD_REPOSITORY.AWR_REPORT_HTML(\\n  (SELECT DBID FROM V$DATABASE),\\n  (SELECT INSTANCE_NUMBER FROM V$INSTANCE),\\n  :begin_snap_id,\\n  :end_snap_id\\n) FROM DUAL;\\n-- Bind :begin_snap_id and :end_snap_id or replace with literal numbers\\n\\nList AWR snapshots:\\n\\nSELECT snap_id, begin_interval_time, end_interval_time\\nFROM dba_hist_snapshot\\nORDER BY snap_id DESC\\nFETCH FIRST 50 ROWS ONLY;\\n\\nTop SQL from AWR range:\\n\\n-- top SQL by elapsed time between AWR snapshots (example)\\nSELECT s.sql_id,\\n       t.sql_text,\\n       SUM(s.elapsed_time_delta) total_elapsed,\\n       SUM(s.cpu_time_delta) total_cpu,\\n       SUM(s.buffer_gets_delta) total_buffer_gets,\\n       SUM(s.executions_delta) total_executions\\nFROM dba_hist_sqlstat s\\nJOIN dba_hist_sqltext t ON s.sql_id = t.sql_id\\nWHERE s.snap_id BETWEEN :begin_snap AND :end_snap\\n  AND s.dbid = (SELECT DBID FROM V$DATABASE)\\nGROUP BY s.sql_id, t.sql_text\\nORDER BY total_elapsed DESC\\nFETCH FIRST 20 ROWS ONLY;"},{"id":"/rman-log-check","metadata":{"permalink":"/engineering-devlog/blog/rman-log-check","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/rman-log-check.md","source":"@site/blog/rman-log-check.md","title":"rman-log-check","description":"---","date":"2026-07-13T03:29:09.000Z","tags":[],"readingTime":0.61,"hasTruncateMarker":false,"authors":[],"frontMatter":{},"unlisted":false,"prevItem":{"title":"AWR-ASH","permalink":"/engineering-devlog/blog/AWR-ASH"}},"content":"---\\nslug: first-production-hotfix\\ntitle: RMAN backup failure and logs check\\nauthors: [VikasPadmashali123]\\ntags: [Rman, backup, logs]\\n---\\n###This post has details of RMAN backup status and logs\\n\\n\\nCheck RMAN backup status and rman backup logs: \\n\\nSTEP 1:  To find the status of the jobs:\\n\\nset lines 300\\n col STATUS format a22\\n col hrs format 999.99\\n select\\n SESSION_KEY, SESSION_RECID, SESSION_STAMP,INPUT_TYPE, STATUS,\\n to_char(START_TIME,\'mm/dd/yy hh24:mi\') start_time,\\n to_char(END_TIME,\'mm/dd/yy hh24:mi\')   end_time,\\n elapsed_seconds/3600                   hrs\\n from V$RMAN_BACKUP_JOB_DETAILS\\n where status=\'RUNNING\'\\n order by session_key;\\n\\n\\nSTEP 2: Check the logs or output of the running RMAN jobs \\nset lines 200\\n set pages 1000\\n select output from GV$RMAN_OUTPUT\\n where session_recid = &SESSION_RECID\\n and session_stamp = &SESSION_STAMP\\n order by recid;"}]}}')}}]);